import MovieItem from "./MovieItem";

function MovieList({ movies, onDelete, onUpdate }) {
    return (
        <div>
            <h2>Movie List</h2>
            {movies.length === 0 ? (
                <p>No movies yet. Add your first movie!</p>
            ) : (
                <ul>
                    {movies.map((movie) => (
                        <MovieItem
                            key={movie.id}
                            movie={movie}
                            onDelete={onDelete}
                            onUpdate={onUpdate}
                        />
                    ))}
                </ul>
            )}
        </div>
    );
}

export default MovieList;
